using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System.IO;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly IWebHostEnvironment _env;
        private readonly FileExtensionContentTypeProvider _contentTypeProvider;

        public FilesController(IWebHostEnvironment env)
        {
            _env = env;
            _contentTypeProvider = new FileExtensionContentTypeProvider();
        }

        [HttpGet("{*fileName}")]
        public IActionResult Get(string fileName)
        {
            if (string.IsNullOrWhiteSpace(fileName) || fileName.IndexOfAny(Path.GetInvalidFileNameChars()) >= 0)
                return BadRequest("Invalid file name.");

            var uploadsPath = Path.Combine(_env.ContentRootPath, "uploads");
            var filePath = Path.Combine(uploadsPath, fileName);

            var normalizedUploadsPath = Path.GetFullPath(uploadsPath);
            var normalizedFilePath = Path.GetFullPath(filePath);

            if (!normalizedFilePath.StartsWith(normalizedUploadsPath, System.StringComparison.OrdinalIgnoreCase))
                return BadRequest("Invalid path.");

            if (!System.IO.File.Exists(normalizedFilePath))
                return NotFound();

            if (!_contentTypeProvider.TryGetContentType(normalizedFilePath, out var contentType))
                contentType = "application/octet-stream";

            var stream = new FileStream(normalizedFilePath, FileMode.Open, FileAccess.Read, FileShare.Read);
            return File(stream, contentType, Path.GetFileName(normalizedFilePath));
        }
    }
}